dashboard.definition:
{
	"title": "HPAs",
	"description": "HPA monitoring dashboard",
	"inputs": {
		"input_Uke7wVO7": {
			"options": {
				"items": ">frame(label, value) | prepend(formattedStatics) | objects()",
				"token": "logs_index_token",
				"selectFirstSearchResult": true
			},
			"title": "Event Logs Index",
			"type": "input.dropdown",
			"dataSources": {
				"primary": "ds_wpLUZiSn"
			},
			"context": {
				"formattedConfig": {
					"number": {
						"prefix": ""
					}
				},
				"formattedStatics": ">statics | formatByType(formattedConfig)",
				"statics": [],
				"label": ">primary | seriesByName(\"logs_index_key\") | renameSeries(\"label\") | formatByType(formattedConfig)",
				"value": ">primary | seriesByName(\"logs_index_value\") | renameSeries(\"value\") | formatByType(formattedConfig)"
			}
		},
		"input_cluster_selector": {
			"dataSources": {
				"primary": "ds_cluster_list"
			},
			"options": {
				"defaultValue": "*",
				"token": "cluster_token"
			},
			"title": "Cluster",
			"type": "input.dropdown"
		},
		"input_global_trp": {
			"options": {
				"defaultValue": "-4h@h,now",
				"token": "global_time"
			},
			"title": "Time Range",
			"type": "input.timerange"
		},
		"input_hpa_selector": {
			"dataSources": {
				"primary": "ds_hpa_list"
			},
			"options": {
				"defaultValue": "*",
				"token": "hpa_token"
			},
			"title": "HPA Name",
			"type": "input.dropdown"
		},
		"input_index_selector": {
			"options": {
				"items": ">frame(label, value) | prepend(formattedStatics) | objects()",
				"token": "index_token",
				"selectFirstSearchResult": true
			},
			"title": "Metrics Index",
			"type": "input.dropdown",
			"dataSources": {
				"primary": "ds_drhfAojL"
			},
			"context": {
				"formattedConfig": {
					"number": {
						"prefix": ""
					}
				},
				"formattedStatics": ">statics | formatByType(formattedConfig)",
				"statics": [],
				"label": ">primary | seriesByName(\"metrics_index_key\") | renameSeries(\"label\") | formatByType(formattedConfig)",
				"value": ">primary | seriesByName(\"metrics_index_value\") | renameSeries(\"value\") | formatByType(formattedConfig)"
			}
		},
		"input_namespace_selector": {
			"dataSources": {
				"primary": "ds_namespace_list"
			},
			"options": {
				"defaultValue": "*",
				"token": "namespace_token"
			},
			"title": "Namespace",
			"type": "input.dropdown"
		}
	},
	"defaults": {
		"dataSources": {
			"ds.search": {
				"options": {
					"queryParameters": {
						"earliest": "$global_time.earliest$",
						"latest": "$global_time.latest$"
					},
					"refresh": "61s"
				}
			}
		}
	},
	"visualizations": {
		"viz_current_replicas": {
			"dataSources": {
				"primary": "ds_replica_metrics"
			},
			"options": {
				"majorValue": "> sparklineValues | lastPoint()",
				"numberPrecision": 0,
				"sparklineValues": "> primary | seriesByName('current_replicas')",
				"unit": "Current"
			},
			"title": "Current Replicas",
			"type": "splunk.singlevalue"
		},
		"viz_desired_replicas": {
			"dataSources": {
				"primary": "ds_replica_metrics"
			},
			"options": {
				"majorValue": "> sparklineValues | lastPoint()",
				"numberPrecision": 0,
				"sparklineValues": "> primary | seriesByName('desired_replicas')",
				"unit": "Desired"
			},
			"title": "Desired Replicas",
			"type": "splunk.singlevalue"
		},
		"viz_hpa_metrics_table": {
			"dataSources": {
				"primary": "ds_hpa_metrics_table"
			},
			"description": "Current metrics driving autoscaling decisions",
			"title": "HPA Metrics Summary",
			"type": "splunk.table",
			"options": {
				"showInternalFields": false,
				"tableFormat": {
					"align": "left"
				}
			}
		},
		"viz_hpa_status": {
			"dataSources": {
				"primary": "ds_hpa_status"
			},
			"description": "Overall HPA effectiveness score",
			"options": {
				"majorColor": "> majorValue | rangeValue(statusColorConfig)",
				"majorValue": "> primary | seriesByName('status_score') | lastPoint()",
				"numberPrecision": 0,
				"statusColorConfig": [
					{
						"color": "#D41F1F",
						"to": 70,
						"value": 0
					},
					{
						"color": "#F5A800",
						"to": 90,
						"value": 70
					},
					{
						"color": "#118832",
						"value": 90
					}
				],
				"unit": "%"
			},
			"title": "HPA Health Status",
			"type": "splunk.singlevalue"
		},
		"viz_max_replicas": {
			"dataSources": {
				"primary": "ds_replica_metrics"
			},
			"options": {
				"majorValue": "> primary | seriesByName('max_replicas') | lastPoint()",
				"numberPrecision": 0,
				"unit": "Max"
			},
			"title": "Max Replicas",
			"type": "splunk.singlevalue"
		},
		"viz_min_replicas": {
			"dataSources": {
				"primary": "ds_replica_metrics"
			},
			"options": {
				"majorValue": "> primary | seriesByName('min_replicas') | lastPoint()",
				"numberPrecision": 0,
				"unit": "Min"
			},
			"title": "Min Replicas",
			"type": "splunk.singlevalue"
		},
		"viz_pod_distribution": {
			"dataSources": {
				"primary": "ds_pod_distribution"
			},
			"description": "Number of pods managed by HPA over time",
			"options": {
				"legendDisplay": "bottom",
				"xField": "_time",
				"yField": "pod_count"
			},
			"title": "Pod Count Distribution",
			"type": "splunk.column"
		},
		"viz_replica_timeline": {
			"dataSources": {
				"primary": "ds_replica_timeline"
			},
			"description": "HPA scaling behavior with min/max boundaries",
			"options": {
				"legendDisplay": "bottom",
				"seriesColorsByField": {
					"current_replicas": "#1E93C6",
					"desired_replicas": "#F5A800",
					"max_replicas": "#D41F1F",
					"min_replicas": "#999999"
				},
				"xField": "_time"
			},
			"title": "Replica Count Over Time",
			"type": "splunk.line"
		},
		"viz_scaling_activity": {
			"dataSources": {
				"primary": "ds_scaling_activity"
			},
			"description": "Scale up vs scale down events",
			"options": {
				"legendDisplay": "bottom",
				"seriesColorsByField": {
					"scale_down": "#F5A800",
					"scale_up": "#118832"
				},
				"stackMode": "stacked",
				"xField": "_time"
			},
			"title": "Scaling Activity (Hourly)",
			"type": "splunk.column"
		},
		"viz_scaling_events_count": {
			"dataSources": {
				"primary": "ds_scaling_events_count"
			},
			"options": {
				"majorValue": "> primary | seriesByName('scale_count') | lastPoint()",
				"numberPrecision": 0,
				"unit": "Events (1h)"
			},
			"title": "Scaling Events",
			"type": "splunk.singlevalue"
		},
		"viz_scaling_history": {
			"dataSources": {
				"primary": "ds_scaling_history"
			},
			"description": "Last 20 scaling events with reasons",
			"options": {
				"actionColorMap": {
					"NoScale": "#FFFFFF",
					"ScaleDown": "#F5A800",
					"ScaleUp": "#118832"
				},
				"backgroundColor": "> table | seriesByName('Action') | matchValue(actionColorMap)"
			},
			"title": "Recent Scaling Decisions",
			"type": "splunk.table"
		},
		"viz_scaling_latency": {
			"dataSources": {
				"primary": "ds_scaling_latency"
			},
			"description": "Time between threshold breach and scaling action",
			"options": {
				"legendDisplay": "off",
				"xField": "_time",
				"yField": "latency_seconds"
			},
			"title": "Scaling Decision Latency",
			"type": "splunk.line"
		},
		"viz_workload_cpu": {
			"dataSources": {
				"primary": "ds_workload_cpu"
			},
			"description": "Average CPU of pods managed by HPA",
			"options": {
				"legendDisplay": "bottom",
				"nullValueDisplay": "connect",
				"xField": "_time",
				"yField": "avg_cpu"
			},
			"title": "Workload CPU Usage",
			"type": "splunk.line"
		}
	},
	"dataSources": {
		"ds_cluster_list": {
			"name": "Cluster List",
			"options": {
				"query": "| mcatalog values(k8s.cluster.name) as cluster WHERE index=$index_token$ | mvexpand cluster | rename cluster as label | eval value=label",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_custom_metrics": {
			"name": "Custom Metrics",
			"options": {
				"query": "| mstats latest(_value) as value WHERE index=$index_token$ metric_name=k8s.hpa.external_metric* k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ k8s.hpa.name=$hpa_token$ by metric_name, k8s.hpa.metric_name | eval \"Custom Metric\"=coalesce(k8s.hpa.metric_name, metric_name), \"Current Value\"=round(value, 2) | table \"Custom Metric\", \"Current Value\"",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_hpa_conditions": {
			"name": "HPA Conditions",
			"options": {
				"query": "| mstats latest(_value) as condition_value WHERE index=$index_token$ metric_name=k8s.hpa.condition* k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ k8s.hpa.name=$hpa_token$ by k8s.hpa.condition, metric_name | eval Status=case(condition_value==1, \"True\", condition_value==0, \"False\", 1==1, \"Unknown\") | rename k8s.hpa.condition as Condition | table Condition, Status | sort Condition",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_hpa_list": {
			"name": "HPA List",
			"options": {
				"query": "| mcatalog values(k8s.hpa.name) as hpa WHERE index=$index_token$ k8s.namespace.name=$namespace_token$ k8s.cluster.name=$cluster_token$ | rename hpa as label | eval value=label",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_hpa_metrics_table": {
			"name": "HPA Metrics Table",
			"options": {
				"query": "| mstats latest(_value) as value WHERE index=$index_token$ metric_name=k8s.hpa.* k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ k8s.hpa.name=$hpa_token$ by metric_name | eval \"Metric\"=replace(metric_name, \"k8s.hpa.\", \"\"), \"Value\"=round(value, 2) | table Metric, Value | sort Metric",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_hpa_status": {
			"name": "HPA Status",
			"options": {
				"query": "| mstats latest(_value) as value WHERE index=$index_token$ (metric_name=kube_horizontalpodautoscaler_status_current_replicas OR metric_name=kube_horizontalpodautoscaler_status_desired_replicas OR metric_name=k8s.hpa.current_replicas OR metric_name=k8s.hpa.desired_replicas) k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ k8s.hpa.name=$hpa_token$ by metric_name \n| eval current=if(match(metric_name, \"current\"), value, null()), desired=if(match(metric_name, \"desired\"), value, null()) \n| stats sum(current) as current, sum(desired) as desired \n| eval status_score=if(current>0 AND desired>0, round((min(current,desired)/max(current,desired))*100, 0), 0)",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_namespace_list": {
			"name": "Namespace List",
			"options": {
				"query": "| mcatalog values(k8s.namespace.name) as namespace WHERE index=$index_token$ | mvexpand namespace | rename namespace as label | eval value=label",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_pod_distribution": {
			"name": "Pod Distribution",
			"options": {
				"query": "| mstats latest(_value) as pod_count WHERE index=$index_token$ metric_name=k8s.hpa.current_replicas k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ k8s.hpa.name=$hpa_token$ span=5m",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_recommendation_efficiency": {
			"name": "Recommendation Efficiency",
			"options": {
				"query": "| mstats latest(_value) as value WHERE index=$index_token$ (metric_name=k8s.hpa.current_replicas OR metric_name=k8s.hpa.desired_replicas OR metric_name=k8s.hpa.current_cpu_utilization OR metric_name=k8s.hpa.target_cpu_utilization) k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ k8s.hpa.name=$hpa_token$ by metric_name | eval current_replicas=if(match(metric_name, \"current_replicas\"), value, null()), desired_replicas=if(match(metric_name, \"desired_replicas\"), value, null()), current_cpu=if(match(metric_name, \"current_cpu\"), value, null()), target_cpu=if(match(metric_name, \"target_cpu\"), value, null()) | stats latest(current_replicas) as current_replicas, latest(desired_replicas) as desired_replicas, latest(current_cpu) as current_cpu, latest(target_cpu) as target_cpu | eval \"Replica Match\"=if(current_replicas==desired_replicas, \"Yes\", \"No (Scaling)\"), \"CPU vs Target\"=round(current_cpu, 1).\"% / \".round(target_cpu, 1).\"%\", \"Efficiency\"=if(current_cpu<=target_cpu*1.1 AND current_cpu>=target_cpu*0.9, \"Optimal\", if(current_cpu>target_cpu*1.1, \"Over Target\", \"Under Target\")) | table \"Replica Match\", \"CPU vs Target\", Efficiency",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_replica_metrics": {
			"name": "Replica Metrics",
			"options": {
				"query": "| mstats latest(_value) as value WHERE index=$index_token$ (metric_name=kube_horizontalpodautoscaler_status_current_replicas OR metric_name=kube_horizontalpodautoscaler_status_desired_replicas OR metric_name=kube_horizontalpodautoscaler_spec_min_replicas OR metric_name=kube_horizontalpodautoscaler_spec_max_replicas OR metric_name=k8s.hpa.current_replicas OR metric_name=k8s.hpa.desired_replicas OR metric_name=k8s.hpa.min_replicas OR metric_name=k8s.hpa.max_replicas) k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ k8s.hpa.name=$hpa_token$ span=5m by metric_name \n| eval current_replicas=if(match(metric_name, \"current\"), value, null()), desired_replicas=if(match(metric_name, \"desired\"), value, null()), min_replicas=if(match(metric_name, \"min\"), value, null()), max_replicas=if(match(metric_name, \"max\"), value, null()) \n| stats latest(current_replicas) as current_replicas, latest(desired_replicas) as desired_replicas, latest(min_replicas) as min_replicas, latest(max_replicas) as max_replicas",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_replica_timeline": {
			"name": "Replica Timeline",
			"options": {
				"query": "| mstats latest(_value) as value WHERE index=$index_token$ (metric_name=kube_horizontalpodautoscaler_status_current_replicas OR metric_name=kube_horizontalpodautoscaler_status_desired_replicas OR metric_name=kube_horizontalpodautoscaler_spec_min_replicas OR metric_name=kube_horizontalpodautoscaler_spec_max_replicas OR metric_name=k8s.hpa.current_replicas OR metric_name=k8s.hpa.desired_replicas OR metric_name=k8s.hpa.min_replicas OR metric_name=k8s.hpa.max_replicas) k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ k8s.hpa.name=$hpa_token$ span=5m by metric_name \n| eval current_replicas=if(match(metric_name, \"current\"), value, null()), desired_replicas=if(match(metric_name, \"desired\"), value, null()), min_replicas=if(match(metric_name, \"min\"), value, null()), max_replicas=if(match(metric_name, \"max\"), value, null()) \n| stats latest(current_replicas) as current_replicas, latest(desired_replicas) as desired_replicas, latest(min_replicas) as min_replicas, latest(max_replicas) as max_replicas by _time",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_scaling_activity": {
			"name": "Scaling Activity",
			"options": {
				"query": "index=k8s_logs k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ (source=*kube-events* OR sourcetype=kube:events) k8s.hpa.name=$hpa_token$ | eval action=case(match(_raw, \"(?i)above target\"), \"scale_up\", match(_raw, \"(?i)below target\"), \"scale_down\", 1==1, \"other\") | where action!=\"other\" | bin _time span=1h | stats count by _time, action | xyseries _time action count | fillnull value=0",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_scaling_events_count": {
			"name": "Scaling Events Count",
			"options": {
				"query": "index=$logs_index_token$ k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ (source=*kube-events* OR sourcetype=kube:events)  (k8s.event.reason=ScaledUp OR k8s.event.reason=ScaledDown OR k8s.event.reason=\"SuccessfulRescale\") earliest=-1h | stats count as scale_count",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_scaling_history": {
			"name": "Scaling History",
			"options": {
				"query": "index=k8s_logs k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ (source=*kube-events* OR sourcetype=kube:events) k8s.hpa.name=$hpa_token$ (k8s.event.reason=ScaledUp OR k8s.event.reason=ScaledDown OR k8s.event.reason=\"SuccessfulRescale\") | head 20 | eval Action=case(match(_raw, \"(?i)above target\"), \"ScaleUp\", match(_raw, \"(?i)below target\"), \"ScaleDown\", 1==1, \"NoScale\") | table _time, Action, k8s.event.reason, _raw | rename _time as Time, k8s.event.reason as Reason, _raw as Message | sort -Time| eval Time = strftime(Time, \"%Y-%m-%d %H:%M:%S.%3N\")",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_scaling_latency": {
			"name": "Scaling Latency",
			"options": {
				"query": "index=k8s_logs k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ (source=*kube-events* OR sourcetype=kube:events) k8s.hpa.name=$hpa_token$ k8s.event.reason=\"SuccessfulRescale\" | streamstats current=f last(_time) as prev_time by k8s.hpa.name | eval latency_seconds=_time-prev_time | where isnotnull(latency_seconds) | timechart span=1h avg(latency_seconds) as latency_seconds",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_workload_cpu": {
			"name": "Workload CPU",
			"options": {
				"query": "| mstats p90(_value) as cpu_core_usage WHERE index=$index_token$ metric_name=container.cpu.usage k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ by k8s.pod.name span=5m\n| join type=left k8s.pod.name \n    [| mstats latest(k8s.pod.phase) as pod_phase WHERE index=$index_token$ k8s.namespace.name=$namespace_token$ k8s.cluster.name=$cluster_token$\n    by k8s.pod.name, k8s.namespace.name, k8s.node.name,\n       k8s.deployment.name, k8s.daemonset.name, k8s.statefulset.name,\n       k8s.replicaset.name, k8s.job.name, k8s.cronjob.name, k8s.hpa.name\n     fillnull_value=\"NA\"\n| rename k8s.namespace.name as namespace , k8s.statefulset.name as statefulset, k8s.deployment.name as deployment, k8s.daemonset.name as daemonset, k8s.job.name as job, k8s.cronjob.name as cronjob, k8s.pod.name as pod, k8s.replicaset.name as replicaset, k8s.node.name as node, k8s.hpa.name as hpa\n| stats count by namespace, pod, deployment, daemonset, statefulset, replicaset, job, cronjob, node, hpa\n| eval workload_type=case(\n    cronjob!=\"NA\", \"Job/CronJob\",\n    job!=\"NA\", \"Job/CronJob\",\n    deployment!=\"NA\", \"Deployment\",\n    daemonset!=\"NA\", \"DaemonSet\",\n    statefulset!=\"NA\", \"StatefulSet\",\n    replicaset!=\"NA\", \"ReplicaSet\",\n    hpa!=\"NA\", \"HPA\",\n    1=1, \"Standalone\"\n)\n| eval statefulset=nullif(statefulset, \"NA\"), deployment=nullif(deployment, \"NA\"), daemonset=nullif(daemonset,\"NA\"), replicaset=nullif(replicaset, \"NA\"), job=nullif(job,\"NA\"), cronjob=nullif(cronjob,\"NA\"), hpa=nullif(hpa, \"NA\")\n| eval workload_name=coalesce(\n    cronjob, job, deployment,\n    daemonset, statefulset,\n    replicaset,hpa\n)\n| table namespace, workload_type, workload_name, pod, node\n| rename namespace as Namespace, workload_type as Workload-Type, workload_name as Workload-Name, pod as k8s.pod.name, node as Node]\n| join type=left Workload-Name \n    [| mcatalog values(k8s.deployment.name) as Workload-Name values(k8s.hpa.name) as HPA-Name WHERE index=$index_token$ metric_name=k8s.hpa.max_replicas\n| eval scaler=\"HPA\"]\n| search  HPA-Name=$hpa_token$| fields _time, cpu_core_usage, k8s.pod.name\n| timechart p90(cpu_core_usage) as Avg_CPU_Core_Usage span=2m by k8s.pod.name",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_drhfAojL": {
